const webhook = $('Webhook').item.json.body.freshdesk_webhook;
const customerData = $('Get row(s) in sheet').item.json;

const isKnownCustomer = customerData && customerData.customer_email;

const enrichedTicket = {
  ticket_id: webhook.ticket_id,
  subject: webhook.ticket_subject,
  description: webhook.ticket_description,
  requester_email: webhook.ticket_requester_email,
  requester_name: webhook.ticket_requester_name,
  created_at: webhook.ticket_created_at,

  is_known_customer: isKnownCustomer,
  customer_segment: isKnownCustomer ? customerData.customer_segment : 'Unknown',

  latest_order: isKnownCustomer ? {
    order_id: customerData.order_id,
    order_date: customerData.order_date,
    order_total: customerData.order_total,
    items: customerData.items,
    shipping_status: customerData.shipping_status,
    tracking_number: customerData.tracking_number
  } : null
};

return enrichedTicket;

const ticket = $json;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      'Authorization': 'Bearer YOUR_GROQ_API_KEY',
      'Content-Type': 'application/json'
    },
    body: {
      model: 'llama-3.3-70b-versatile',
      messages: [
        {
          role: 'system',
          content: `You are a customer support classifier. Classify tickets into exactly ONE category:

SHIPPING: Questions about an EXISTING order - tracking, delivery status, delays, where is my package
RETURN: Requests to return or exchange items from an EXISTING order
PRODUCT_QUESTION: PRE-SALE questions (before purchase) - shipping costs, delivery times, product availability, do you ship to X, product details, sizing, colors
ORDER_CHANGE: Requests to modify or cancel an EXISTING order
COMPLAINT: Expressions of dissatisfaction, damaged items, quality issues
ESCALATE: Requests for manager, threats, repeated issues, very angry customers

IMPORTANT DISTINCTION:
- "Where is my order?" = SHIPPING (existing order)
- "Do you ship to Canada?" = PRODUCT_QUESTION (pre-sale, no order yet)
- "How long does shipping take?" = PRODUCT_QUESTION (pre-sale inquiry)
- "My order has not arrived" = SHIPPING (existing order)

Rate urgency 1-5:
1 = Low - General inquiry
2 = Medium-Low - Standard request  
3 = Medium - Needs attention within 24 hours
4 = High - Customer is frustrated
5 = Critical - Very angry, threatening

Respond with JSON only: {"category": "NAME", "urgency": NUMBER, "reasoning": "explanation"}`
        },
        {
          role: 'user',
          content: `Classify this ticket:

Subject: ${ticket.subject}
Message: ${ticket.description}
Customer: ${ticket.requester_email}
Segment: ${ticket.customer_segment}`
        }
      ],
      temperature: 0.1,
      max_tokens: 200
    },
    json: true
  });

  const classification = JSON.parse(response.choices[0].message.content);

  return {
    ...ticket,
    classification: classification,
    classification_error: false
  };

} catch (error) {
  return {
    ...ticket,
    classification: {
      category: 'ESCALATE',
      urgency: 5,
      reasoning: 'AUTO-ESCALATED: Classification system failed. Error: ' + error.message
    },
    classification_error: true
  };
}

const data = $json;

try {
  await this.helpers.httpRequest({
    method: 'PUT',
    url: `https://YOUR_SUBDOMAIN.freshdesk.com/api/v2/tickets/${data.ticket_id}`,
    headers: {
      'Content-Type': 'application/json'
    },
    auth: {
      username: 'YOUR_FRESHDESK_API_KEY',
      password: 'X'
    },
    body: {
      tags: [
        data.classification.category,
        `urgency-${data.classification.urgency}`,
        `segment-${data.customer_segment || 'Unknown'}`
      ]
    },
    json: true
  });

  return {
    ...data,
    freshdesk_updated: true,
    tag_error: false
  };

} catch (error) {
  return {
    ...data,
    freshdesk_updated: false,
    tag_error: true,
    tag_error_message: error.message
  };
}

