const data = $json;

const assignedTo = 'shipping.team@urbannest.com';

const hasOrder = data.latest_order && data.latest_order.order_id;
let draftResponse = '';

try {
  if (!data.is_known_customer) {
    draftResponse = `To locate your order, please provide your order number and the email address used when placing the order.

Once we have this information, we can provide you with the current status and tracking details.`;

  } else if (!hasOrder) {
    draftResponse = `We could not find any orders associated with your email address.

Please provide your order number so we can look up the status. If you placed the order using a different email address, please let us know.`;

  } else {
    const order = data.latest_order;
    const status = order.shipping_status || 'processing';
    const tracking = order.tracking_number;
    const items = order.items || 'your items';

    if (status === 'delivered') {
      draftResponse = `Your order ${order.order_id} (${items}) was delivered.

Tracking number: ${tracking}

If you did not receive the package, please check with neighbors or your building management. You can also verify delivery details using the tracking number on the carrier website.

If the package is still missing, reply to this message and we will open an investigation with the carrier.`;

    } else if (status === 'in_transit') {
      draftResponse = `Your order ${order.order_id} (${items}) is currently in transit.

Tracking number: ${tracking}

You can track your package using this number on the carrier website. Estimated delivery is within 2-5 business days.`;

    } else if (status === 'delayed') {
      draftResponse = `Your order ${order.order_id} (${items}) is currently delayed.

Tracking number: ${tracking}

We apologize for the inconvenience. The carrier has reported a delay, but your package is still on its way. You will receive an email notification when it is out for delivery.`;

    } else if (status === 'shipped') {
      draftResponse = `Your order ${order.order_id} (${items}) has shipped.

Tracking number: ${tracking || 'will be available within 24 hours'}

You will receive tracking updates via email as your package moves through the delivery network.`;

    } else {
      draftResponse = `Your order ${order.order_id} (${items}) is currently being processed.

Once shipped, you will receive an email with tracking information. Standard orders ship within 1-2 business days.`;
    }
  }

  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://YOUR_SUBDOMAIN.freshdesk.com/api/v2/tickets/${data.ticket_id}/notes`,
    headers: {
      'Content-Type': 'application/json'
    },
    auth: {
      username: 'YOUR_FRESHDESK_API_KEY',
      password: 'X'
    },
    body: {
      body: `<b>🤖 AI-Generated Draft Response:</b><br><br>${draftResponse.replace(/\n\n/g, '<br><br>').replace(/\n/g, '<br>')}`,
      private: true
    },
    json: true
  });

  return {
    ...data,
    draft_generated: true,
    draft_response: draftResponse,
    assigned_to: assignedTo,
    handler: 'shipping',
    handler_error: false
  };

} catch (error) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://YOUR_SUBDOMAIN.freshdesk.com/api/v2/tickets/${data.ticket_id}/notes`,
      headers: {
        'Content-Type': 'application/json'
      },
      auth: {
        username: 'YOUR_FRESHDESK_API_KEY',
        password: 'X'
      },
      body: {
        body: `<b>⚠️ System Notice:</b> Automated response generation failed. Please handle this ticket manually.<br><br>Error: ${error.message}`,
        private: true
      },
      json: true
    });
  } catch (noteError) {}

  return {
    ...data,
    draft_generated: false,
    draft_response: null,
    assigned_to: assignedTo,
    handler: 'shipping',
    handler_error: true,
    handler_error_message: error.message
  };
}

